        return np.linalg.norm(point1 - point2)

    def estimate_congestion(customer_pos):
        own_distance = calculate_distance(cur_truck_pos, customer_pos)
        congestion = sum(calculate_distance(pos, customer_pos) < own_distance for pos in all_truck_pos)
        return congestion

    def estimate_future_travel_impact(customer_index):
        future_total_distance = 0
        for other_idx, other_customer in enumerate(unvisited_customers):
            if other_idx != customer_index:
                future_total_distance += calculate_distance(other_customer, unvisited_customers[customer_index])
        return future_total_distance / (len(unvisited_customers) - 1) if len(unvisited_customers) > 1 else 0

    best_node = None
    min_score = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        time_window = time_windows[idx]
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_window

        congestion = estimate_congestion(customer_pos)
        future_travel_impact = estimate_future_travel_impact(idx)

        if arrival_time < start_window:
            wait_penalty = start_window - arrival_time
        elif arrival_time > end_window:
            wait_penalty = (arrival_time - end_window) * 100
        else:
            wait_penalty = 0

        score = travel_time + wait_penalty + 2 * congestion + 0.5 * future_travel_impact

        if score < min_score:
            min_score = score
            best_node = idx

    return best_node

